### Exercise 8: 实现 printf 系统调用

**文件位置：** `user/chcore-libc/musl-libc/src/chcore-port/chcore_stdout_write.c`

**核心代码：**

```c
#include <stdio.h>
#include <unistd.h>
#include "chcore_syscall.h"

// 系统调用号定义（在 chcore_syscall.h 中）
// #define CHCORE_SYS_putstr  XX

/**
 * chcore_stdout_write - 向标准输出写入字符串
 * @str: 要输出的字符串
 * 
 * 返回：成功写入的字符数，失败返回 -1
 */
ssize_t chcore_stdout_write(const char *str)
{
        if (!str)
                return -1;

        // 计算字符串长度
        size_t len = 0;
        const char *p = str;
        while (*p++)
                len++;

        // 通过系统调用输出字符串
        // 使用 chcore_syscall2: 系统调用号 + 2 个参数
        long ret = chcore_syscall2(CHCORE_SYS_putstr, 
                                   (unsigned long)str, 
                                   (unsigned long)len);

        if (ret < 0)
                return -1;

        return (ssize_t)ret;
}

/**
 * put - 向终端输出字符串（辅助函数）
 * @str: 要输出的字符串
 */
void put(const char *str)
{
        chcore_stdout_write(str);
}
```

**对应的内核系统调用处理（kernel/syscall.c）：**

```c
/**
 * sys_putstr - 内核态字符串输出系统调用
 * @str: 用户态字符串指针
 * @len: 字符串长度
 * 
 * 返回：成功输出的字符数
 */
long sys_putstr(unsigned long str, unsigned long len)
{
        char *kstr;
        int ret;

        // 从用户态拷贝字符串到内核
        kstr = kmalloc(len + 1);
        if (!kstr)
                return -ENOMEM;

        ret = copy_from_user(kstr, (void *)str, len);
        if (ret) {
                kfree(kstr);
                return -EFAULT;
        }
        kstr[len] = '\0';

        // 通过串口输出
        uart_putstr(kstr);

        kfree(kstr);
        return len;
}
```

**代码说明：**

1. **用户态**：`chcore_stdout_write` 使用 `chcore_syscall2` 发起系统调用，传递字符串指针和长度
2. **内核态**：`sys_putstr` 从用户态拷贝字符串，通过 `uart_putstr` 输出到串口
3. **系统调用表**：需要在 `kernel/syscall.c` 的 `syscall_table` 中注册 `sys_putstr`

