## Part 1 线程生命周期管理

### 实验概述

本部分主要完成 ChCore 微内核中第一个用户态进程和线程的创建，理解内核态到用户态的切换过程。涉及能力组（cap_group）创建、ELF 程序加载、线程上下文初始化等核心内容。

---

### Exercise 1: 能力组创建

**文件位置：** `kernel/object/cap_group.c`

**核心代码：**

```c
/* This is for creating the first (init) user process. */
struct cap_group *create_root_cap_group(char *name, size_t name_len)
{
        struct cap_group *cap_group;
        struct vmspace *vmspace;
        cap_t slot_id;

        // 1. 分配 cap_group 对象
        cap_group = obj_alloc(TYPE_CAP_GROUP, sizeof(*cap_group));
        if (!cap_group) {
                kwarn("failed alloc cap_group in %s\n", __func__);
                return NULL;
        }

        // 2. 初始化能力组，使用固定的 ROOT_CAP_GROUP_BADGE
        cap_group_init(cap_group,
                       BASE_OBJECT_NUM,
                       /* Fixed badge */ ROOT_CAP_GROUP_BADGE);

        // 3. 将 cap_group 自身注册到能力组的 slot 0
        slot_id = cap_alloc(cap_group, cap_group);
        BUG_ON(slot_id != CAP_GROUP_OBJ_ID);

        // 4. 创建 vmspace 对象用于虚拟地址空间管理
        vmspace = obj_alloc(TYPE_VMSPACE, sizeof(*vmspace));
        if (!vmspace) {
                kwarn("failed alloc vmspace in %s\n", __func__);
                return NULL;
        }

        // 5. 初始化 vmspace，使用固定的 PCID 1（PCID 0 未使用）
        vmspace_init(vmspace, ROOT_PROCESS_PCID);

        // 6. 将 vmspace 注册到能力组的 slot 1
        slot_id = cap_alloc(cap_group, vmspace);
        BUG_ON(slot_id != VMSPACE_OBJ_ID);

        // 7. 设置能力组名称（进程名），便于调试
        memset(cap_group->cap_group_name, 0, MAX_GROUP_NAME_LEN + 1);
        if (name_len > MAX_GROUP_NAME_LEN)
                name_len = MAX_GROUP_NAME_LEN;
        memcpy(cap_group->cap_group_name, name, name_len);

        // 8. 设置为全局根能力组
        root_cap_group = cap_group;

        return cap_group;
}

/* 系统调用：创建新的能力组 */
long sys_create_cap_group(unsigned long cap_group_args_p)
{
        struct cap_group *cap_group, *parent_cap_group;
        struct create_cap_group_args args;
        cap_t slot_id;
        struct vmspace *vmspace;

        // 1. 从用户态拷贝参数到内核
        if (copy_from_user(&args, (void *)cap_group_args_p, sizeof(args)))
                return -EFAULT;

        // 2. 获取当前进程的能力组（父能力组）
        parent_cap_group = current_cap_group();
        if (!parent_cap_group)
                return -EINVAL;

        // 3. 分配新的 cap_group 对象
        cap_group = obj_alloc(TYPE_CAP_GROUP, sizeof(*cap_group));
        if (!cap_group)
                return -ENOMEM;

        // 4. 初始化新能力组，badge 由系统自动分配
        cap_group_init(cap_group, BASE_OBJECT_NUM, 0);

        // 5. 将新 cap_group 注册到自身的 slot 0
        slot_id = cap_alloc(cap_group, cap_group);
        if (slot_id < 0)
                return -ENOMEM;

        // 6. 创建新的 vmspace
        vmspace = obj_alloc(TYPE_VMSPACE, sizeof(*vmspace));
        if (!vmspace)
                return -ENOMEM;

        // 7. 初始化 vmspace，分配新的 PCID
        vmspace_init(vmspace, 0);

        // 8. 将 vmspace 注册到新能力组的 slot 1
        slot_id = cap_alloc(cap_group, vmspace);
        if (slot_id < 0)
                return -ENOMEM;

        // 9. 设置能力组名称
        memset(cap_group->cap_group_name, 0, MAX_GROUP_NAME_LEN + 1);
        if (args.name_len > MAX_GROUP_NAME_LEN)
                args.name_len = MAX_GROUP_NAME_LEN;
        if (copy_from_user(cap_group->cap_group_name, args.name, args.name_len))
                return -EFAULT;

        return cap_group->badge;
}
```

**代码说明：**

`create_root_cap_group` 函数创建系统的第一个能力组（根能力组），主要完成以下工作：

1. **对象分配**：使用 `obj_alloc` 分配 `cap_group` 和 `vmspace` 对象，这是 ChCore 中所有内核对象的统一分配方式
2. **能力组初始化**：调用 `cap_group_init` 初始化能力组的内部结构，包括槽位表、线程列表等
3. **自引用注册**：将能力组自身注册到 slot 0，这使得根能力组成为系统的权限起点
4. **虚拟地址空间**：创建并注册 `vmspace` 对象，用于管理进程的虚拟内存
5. **命名**：设置能力组名称便于调试

`sys_create_cap_group` 是用户态创建新进程的系统调用接口，与根能力组创建的区别在于：

- 需要从用户态拷贝参数，进行安全性检查
- badge 由系统自动分配而非固定值
- 权限继承自父能力组

---

### Exercise 2: ELF 加载

**文件位置：** `kernel/object/thread.c`

**核心代码：**

```c
/*
 * The root_thread is actually a first user thread
 * which has no difference with other user threads
 */
void create_root_thread(void)
{
        struct cap_group *root_cap_group;
        cap_t thread_cap;
        struct thread *root_thread;
        char data[8];
        int ret;
        cap_t stack_pmo_cap;
        struct thread *thread;
        struct pmobject *stack_pmo;
        struct vmspace *init_vmspace;
        vaddr_t stack;
        vaddr_t kva;
        struct process_metadata meta;

        // ========== 1. 读取 ELF 元数据 ==========
        // 从内核镜像后链接的 procmgr 二进制中读取入口点、标志、程序头等信息
        memcpy(data,
               (void *)((unsigned long)&binary_procmgr_bin_start
                        + ROOT_ENTRY_OFF),
               sizeof(data));
        meta.entry = (unsigned long)be64_to_cpu(*(u64 *)data);

        memcpy(data,
               (void *)((unsigned long)&binary_procmgr_bin_start
                        + ROOT_FLAGS_OFF),
               sizeof(data));
        meta.flags = (unsigned long)be64_to_cpu(*(u64 *)data);

        memcpy(data,
               (void *)((unsigned long)&binary_procmgr_bin_start
                        + ROOT_PHENT_SIZE_OFF),
               sizeof(data));
        meta.phentsize = (unsigned long)be64_to_cpu(*(u64 *)data);

        memcpy(data,
               (void *)((unsigned long)&binary_procmgr_bin_start
                        + ROOT_PHNUM_OFF),
               sizeof(data));
        meta.phnum = (unsigned long)be64_to_cpu(*(u64 *)data);

        memcpy(data,
               (void *)((unsigned long)&binary_procmgr_bin_start
                        + ROOT_PHDR_ADDR_OFF),
               sizeof(data));
        meta.phdr_addr = (unsigned long)be64_to_cpu(*(u64 *)data);

        // ========== 2. 创建根能力组 ==========
        root_cap_group = create_root_cap_group(ROOT_NAME, strlen(ROOT_NAME));
        BUG_ON(!root_cap_group);

        // 获取初始化虚拟地址空间
        init_vmspace = obj_get(root_cap_group, VMSPACE_OBJ_ID, TYPE_VMSPACE);
        BUG_ON(!init_vmspace);

        // ========== 3. 分配用户栈 ==========
        stack_pmo_cap = create_pmo(ROOT_THREAD_STACK_SIZE,
                                   PMO_ANONYM,
                                   root_cap_group,
                                   0,
                                   &stack_pmo,
                                   PMO_ALL_RIGHTS);
        BUG_ON(stack_pmo_cap < 0);

        // 将栈 PMO 映射到虚拟地址空间
        ret = vmspace_map_range(init_vmspace,
                                ROOT_THREAD_STACK_BASE,
                                ROOT_THREAD_STACK_SIZE,
                                VMR_READ | VMR_WRITE,
                                stack_pmo);
        BUG_ON(ret != 0);

        // ========== 4. 分配线程对象 ==========
        thread = obj_alloc(TYPE_THREAD, sizeof(*thread));
        BUG_ON(thread == NULL);

        // ========== 5. 加载 ELF 程序段 ==========
        for (int i = 0; i < meta.phnum; i++) {
                unsigned int flags;
                unsigned long offset, vaddr, filesz, memsz;

                // 读取程序头表项中的各个字段
                memcpy(data,
                       (void *)((unsigned long)&binary_procmgr_bin_start
                                + ROOT_PHDR_OFF + i * ROOT_PHENT_SIZE
                                + PHDR_FLAGS_OFF),
                       sizeof(data));
                flags = (unsigned int)le32_to_cpu(*(u32 *)data);

                memcpy(data,
                       (void *)((unsigned long)&binary_procmgr_bin_start
                                + ROOT_PHDR_OFF + i * ROOT_PHENT_SIZE
                                + PHDR_OFFSET_OFF),
                       sizeof(data));
                offset = (unsigned long)le64_to_cpu(*(u64 *)data);

                memcpy(data,
                       (void *)((unsigned long)&binary_procmgr_bin_start
                                + ROOT_PHDR_OFF + i * ROOT_PHENT_SIZE
                                + PHDR_VADDR_OFF),
                       sizeof(data));
                vaddr = (unsigned long)le64_to_cpu(*(u64 *)data);

                memcpy(data,
                       (void *)((unsigned long)&binary_procmgr_bin_start
                                + ROOT_PHDR_OFF + i * ROOT_PHENT_SIZE
                                + PHDR_FILESZ_OFF),
                       sizeof(data));
                filesz = (unsigned long)le64_to_cpu(*(u64 *)data);

                memcpy(data,
                       (void *)((unsigned long)&binary_procmgr_bin_start
                                + ROOT_PHDR_OFF + i * ROOT_PHENT_SIZE
                                + PHDR_MEMSZ_OFF),
                       sizeof(data));
                memsz = (unsigned long)le64_to_cpu(*(u64 *)data);

                struct pmobject *segment_pmo;
                size_t pmo_size = ROUND_UP(memsz, PAGE_SIZE);
                vaddr_t segment_content_kvaddr =
                        ((unsigned long)&binary_procmgr_bin_start) + offset;

                // 为每个段分配 PMO
                ret = create_pmo(PAGE_SIZE,
                                 PMO_DATA,
                                 root_cap_group,
                                 0,
                                 &segment_pmo,
                                 PMO_ALL_RIGHTS);
                BUG_ON(ret < 0);

                // 设置 PMO 的物理地址为内核镜像中的段内容
                kfree((void *)phys_to_virt(segment_pmo->start));
#if CHCORE_ARCH_X86_64
                segment_pmo->start =
                        embedded_bin_virt_to_phys(segment_content_kvaddr);
                segment_pmo->size = pmo_size;
#else
                segment_pmo->start = virt_to_phys(segment_content_kvaddr);
                segment_pmo->size = pmo_size;
#endif

                // 根据程序头标志设置虚拟内存权限
                unsigned vmr_flags = 0;
                if (flags & PHDR_FLAGS_R)
                        vmr_flags |= VMR_READ;
                if (flags & PHDR_FLAGS_W)
                        vmr_flags |= VMR_WRITE;
                if (flags & PHDR_FLAGS_X)
                        vmr_flags |= VMR_EXEC;

                // 将段映射到虚拟地址空间
                ret = vmspace_map_range(init_vmspace,
                                        vaddr,
                                        segment_pmo->size,
                                        vmr_flags,
                                        segment_pmo);
                BUG_ON(ret < 0);
        }

        obj_put(init_vmspace);

        // ========== 6. 准备用户栈 ==========
        stack = ROOT_THREAD_STACK_BASE + ROOT_THREAD_STACK_SIZE;

        // 为主栈分配物理页
        kva = (vaddr_t)get_pages(0);
        BUG_ON(kva == 0);

        // 提交页到栈 PMO
        commit_page_to_pmo(stack_pmo,
                           ROOT_THREAD_STACK_SIZE / PAGE_SIZE - 1,
                           virt_to_phys((void *)kva));

        // 准备环境变量和参数
        prepare_env((char *)kva, stack, ROOT_NAME, &meta);
        stack -= ENV_SIZE_ON_STACK;

        // ========== 7. 初始化线程 ==========
        ret = thread_init(thread,
                          root_cap_group,
                          stack,
                          meta.entry,
                          ROOT_THREAD_PRIO,
                          TYPE_USER,
                          smp_get_cpu_id());
        BUG_ON(ret != 0);

        // ========== 8. 添加到能力组的线程列表 ==========
        lock(&root_cap_group->threads_lock);
        list_add(&thread->node, &root_cap_group->thread_list);
        root_cap_group->thread_cnt += 1;
        unlock(&root_cap_group->threads_lock);

        // ========== 9. 分配线程能力 ==========
        thread_cap = cap_alloc(root_cap_group, thread);
        BUG_ON(thread_cap < 0);
        thread->cap = thread_cap;

        // ========== 10. 刷新缓存 ==========
        flush_idcache();

        // ========== 11. 加入调度队列 ==========
        root_thread = obj_get(root_cap_group, thread_cap, TYPE_THREAD);
        BUG_ON(sched_enqueue(root_thread));
        obj_put(root_thread);
}
```

**代码说明：**

`create_root_thread` 函数完成第一个用户线程的创建和 ELF 程序加载，主要步骤包括：

1. **读取 ELF 元数据**：从内核镜像中嵌入的 procmgr 二进制读取入口点、程序头表等信息
2. **创建根能力组**：调用 Exercise 1 中完成的 `create_root_cap_group`
3. **分配用户栈**：创建 PMO 并映射到虚拟地址空间
4. **加载 ELF 段**：遍历程序头表，为每个段（代码段、数据段等）分配 PMO 并设置相应权限（读/写/执行）
5. **准备运行环境**：在用户栈上设置环境变量和命令行参数
6. **初始化线程**：设置线程上下文、优先级等
7. **加入调度**：将线程添加到就绪队列等待执行

