### Exercise 5: 异常向量表配置

**文件位置：** `kernel/arch/aarch64/irq/irq_entry.S`

**核心代码：**

```assembly
/*
 * Exception Vector Table for EL1
 * 每个异常级别有 16 个向量条目，对应不同的异常来源和类型
 */

    .align 11  // 异常向量表必须 2KB 对齐 (2^11)

exception_vectors_el1:
    // ========== 当前 SP: SP_EL0 (EL0 使用 SP_EL0 进入异常) ==========

    // 0x000: Synchronous Exception from EL0 (系统调用等)
    .globl vector_sync_el0t
vector_sync_el0t:
    save_context              // 保存用户态上下文
    mov x0, sp                // 传递栈指针给 C 处理函数
    mov x1, #SYNC_EXCEPTION   // 传递异常类型
    bl handle_entry_c         // 调用 C 语言异常处理函数
    restore_context           // 恢复上下文
    eret                      // 返回用户态

    // 0x080: IRQ Exception from EL0
    .globl vector_irq_el0t
vector_irq_el0t:
    save_context
    mov x0, sp
    mov x1, #IRQ_EXCEPTION
    bl handle_entry_c
    restore_context
    eret

    // 0x100: FIQ Exception from EL0
    .globl vector_fiq_el0t
vector_fiq_el0t:
    save_context
    mov x0, sp
    mov x1, #FIQ_EXCEPTION
    bl handle_entry_c
    restore_context
    eret

    // 0x180: SError Exception from EL0
    .globl vector_error_el0t
vector_error_el0t:
    save_context
    mov x0, sp
    mov x1, #ERROR_EXCEPTION
    bl handle_entry_c
    restore_context
    eret

    // ========== 当前 SP: SP_EL1 (EL1 使用 SP_EL1 进入异常) ==========

    // 0x200: Synchronous Exception from EL1 (当前 EL1h 模式)
    .globl vector_sync_el1h
vector_sync_el1h:
    save_context
    mov x0, sp
    mov x1, #SYNC_EXCEPTION
    bl handle_entry_c
    restore_context
    eret

    // 0x280: IRQ Exception from EL1
    .globl vector_irq_el1h
vector_irq_el1h:
    save_context
    mov x0, sp
    mov x1, #IRQ_EXCEPTION
    bl handle_entry_c
    restore_context
    eret

    // 0x300: FIQ Exception from EL1
    .globl vector_fiq_el1h
vector_fiq_el1h:
    save_context
    mov x0, sp
    mov x1, #FIQ_EXCEPTION
    bl handle_entry_c
    restore_context
    eret

    // 0x380: SError Exception from EL1
    .globl vector_error_el1h
vector_error_el1h:
    save_context
    mov x0, sp
    mov x1, #ERROR_EXCEPTION
    bl handle_entry_c
    restore_context
    eret

    // ========== 其他向量条目 (未使用，跳转到意外处理程序) ==========

    // 以下条目在 ChCore 中暂不使用，跳转到意外处理程序
    .globl unexpected_handler
unexpected_handler:
    save_context
    mov x0, sp
    mov x1, #UNEXPECTED_EXCEPTION
    bl handle_entry_c
    restore_context
    eret

// 填充完整的 16 个向量条目（每个间隔 0x80 字节）
    .balign 0x80
    b unexpected_handler  // EL0t with SP_EL1 - 不应该发生

    .balign 0x80
    b unexpected_handler  // EL0h with SP_EL0 - 不应该发生

    .balign 0x80
    b unexpected_handler  // EL0h with SP_EL1 - 不应该发生

    // ... 其他未使用的向量条目类似处理

/*
 * 异常向量表初始化函数
 */
void arch_interrupt_init(void)
{
    // 设置 EL1 异常向量基地址寄存器
    write_vbar_el1((u64)exception_vectors_el1);

    // 启用中断
    enable_irq();
}
```

**代码说明：**

异常向量表是 AArch64 架构中异常处理的核心机制：

1. **对齐要求**：向量表必须 2KB 对齐（`.align 11`），因为硬件直接使用该地址作为基地址
2. **16 个条目**：每个异常级别有 16 个向量，由以下因素组合：
   - 异常来源：EL0（用户态）或 EL1（内核态）
   - 当前栈指针：SP_EL0 或 SP_EL1
   - 异常类型：同步异常、IRQ、FIQ、SError
3. **处理流程**：
   - `save_context`：保存所有通用寄存器到内核栈
   - 调用 `handle_entry_c`：C 语言异常处理函数，根据异常类型分发处理
   - `restore_context`：恢复寄存器
   - `eret`：异常返回，根据 SPSR_EL1 恢复到相应的异常级别

对于 ChCore，关键的向量是：
- `vector_sync_el0t`：处理用户态系统调用（svc 指令）
- `vector_sync_el1h`：处理内核态同步异常
- `vector_irq_el1h`：处理硬件中断

