### Exercise 6: 上下文保存与内核栈切换

**文件位置：** `kernel/arch/aarch64/irq/irq_entry.S`

**核心代码：**

```assembly
/*
 * 保存执行上下文的宏
 * 在内核栈上分配 ARCH_EXEC_CONT_SIZE 空间保存所有寄存器
 */
.macro save_context
    // 在内核栈上分配空间 (32 个寄存器 * 8 字节 = 256 字节)
    sub sp, sp, #ARCH_EXEC_CONT_SIZE

    // 保存通用寄存器 x0-x29 (成对保存提高效率)
    stp x0, x1, [sp, #16 * 0]
    stp x2, x3, [sp, #16 * 1]
    stp x4, x5, [sp, #16 * 2]
    stp x6, x7, [sp, #16 * 3]
    stp x8, x9, [sp, #16 * 4]
    stp x10, x11, [sp, #16 * 5]
    stp x12, x13, [sp, #16 * 6]
    stp x14, x15, [sp, #16 * 7]
    stp x16, x17, [sp, #16 * 8]
    stp x18, x19, [sp, #16 * 9]
    stp x20, x21, [sp, #16 * 10]
    stp x22, x23, [sp, #16 * 11]
    stp x24, x25, [sp, #16 * 12]
    stp x26, x27, [sp, #16 * 13]
    stp x28, x29, [sp, #16 * 14]

    // 保存特殊寄存器
    mov x21, sp_el0           // 用户态栈指针
    mrs x22, elr_el1          // 异常链接寄存器（返回地址）
    mrs x23, spsr_el1         // 保存的程序状态寄存器
    stp x22, x23, [sp, #16 * 15]
    stp x30, x21, [sp, #16 * 16]  // x30 (LR) 和 sp_el0
.endm

/*
 * 恢复执行上下文的宏
 * 与 save_context 对应，从内核栈恢复所有寄存器
 */
.macro restore_context
    // 恢复特殊寄存器
    ldp x22, x23, [sp, #16 * 15]
    ldp x30, x21, [sp, #16 * 16]
    msr sp_el0, x21           // 恢复用户态栈指针
    msr elr_el1, x22          // 恢复返回地址
    msr spsr_el1, x23         // 恢复程序状态寄存器

    // 恢复通用寄存器 x0-x29
    ldp x0, x1, [sp, #16 * 0]
    ldp x2, x3, [sp, #16 * 1]
    ldp x4, x5, [sp, #16 * 2]
    ldp x6, x7, [sp, #16 * 3]
    ldp x8, x9, [sp, #16 * 4]
    ldp x10, x11, [sp, #16 * 5]
    ldp x12, x13, [sp, #16 * 6]
    ldp x14, x15, [sp, #16 * 7]
    ldp x16, x17, [sp, #16 * 8]
    ldp x18, x19, [sp, #16 * 9]
    ldp x20, x21, [sp, #16 * 10]
    ldp x22, x23, [sp, #16 * 11]
    ldp x24, x25, [sp, #16 * 12]
    ldp x26, x27, [sp, #16 * 13]
    ldp x28, x29, [sp, #16 * 14]

    // 释放栈空间
    add sp, sp, #ARCH_EXEC_CONT_SIZE
.endm

/*
 * 切换到 CPU 内核栈
 * 从 TPIDR_EL1 读取 per_cpu_info，获取 cpu_stack 地址
 */
.globl switch_to_cpu_stack
switch_to_cpu_stack:
    // 从 TPIDR_EL1 读取当前 CPU 的 per_cpu_info 指针
    mrs x0, tpidr_el1

    // 获取 per_cpu_info->cpu_stack 地址
    // 假设 cpu_stack 是 per_cpu_info 的第一个字段
    ldr x1, [x0]

    // 计算内核栈顶（栈向下增长）
    // cpu_stack 指向栈底，需要加上栈大小
    mov x2, #CPU_STACK_SIZE
    add x1, x1, x2

    // 切换到内核栈
    mov sp, x1

    ret

/*
 * 异常进入处理
 * 保存上下文并切换到内核栈
 */
.globl exception_enter
exception_enter:
    // 1. 保存用户态上下文
    save_context

    // 2. 切换到内核栈
    bl switch_to_cpu_stack

    // 3. 调用 C 语言异常处理函数
    // x0 = sp (指向保存的上下文)
    mov x0, sp
    bl handle_entry_c

    // 4. 准备返回
    ret

/*
 * 异常退出处理
 * 恢复上下文并返回用户态
 */
.globl exception_exit
exception_exit:
    // 1. 恢复用户态上下文
    restore_context

    // 2. 返回用户态
    eret
```

**代码说明：**

1. **save_context/restor_context**：
   - 在内核栈上分配 256 字节空间保存 32 个寄存器
   - 使用 `stp`/`ldp` 成对存储/加载提高效率
   - 保存关键寄存器：`sp_el0`（用户栈）、`elr_el1`（返回地址）、`spsr_el1`（状态寄存器）

2. **switch_to_cpu_stack**：
   - 从 `TPIDR_EL1` 寄存器读取当前 CPU 的 `per_cpu_info` 结构
   - 获取 `cpu_stack` 地址并计算栈顶
   - 切换 `sp` 到内核栈

3. **exception_enter/exception_exit**：
   - 进入时保存上下文并切换内核栈
   - 退出时恢复上下文并执行 `eret` 返回用户态

